1	import { Image } from "@tarojs/components";
2	import { ICON_PATHS, PLACEHOLDER } from "./iconPaths";
3	
4	export type IconName =
5	  | "dumbbell" | "book-open" | "sparkles" | "briefcase"
6	  | "brain" | "landmark" | "globe" | "home"
7	  | "target" | "palette" | "music" | "pen"
8	  | "lotus" | "runner" | "heart-pulse" | "laptop"
9	  | "clipboard" | "film" | "message-circle" | "compass"
10	  | "microscope" | "bar-chart" | "lightbulb" | "star"
11	  | "package" | "bot" | "award" | "clipboard-list"
12	  | "check" | "x"
13	  | "mood-1" | "mood-2" | "mood-3" | "mood-4" | "mood-5";
14	
15	export type IconColor = "primary" | "secondary" | "accent" | "muted" | "faded";
16	
17	export interface IconProps {
18	  name: IconName;
19	  size?: number;
20	  color?: IconColor;
21	}
22	
23	const COLOR_MAP: Record<IconColor, string> = {
24	  primary: "#e8e0d6",
25	  secondary: "#a89f92",
26	  accent: "#c4843e",
27	  muted: "#7a7268",
28	  faded: "#4a4540",
29	};
30	
31	/** 纯 JS base64 编码（ASCII 安全，不依赖 btoa / TextEncoder） */
32	function toBase64(str: string): string {
33	  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
34	  const bytes: number[] = [];
35	  for (let i = 0; i < str.length; i++) {
36	    bytes.push(str.charCodeAt(i));
37	  }
38	
39	  let result = "";
40	  for (let i = 0; i < bytes.length; i += 3) {
41	    const a = bytes[i];
42	    const b = i + 1 < bytes.length ? bytes[i + 1] : null;
43	    const c = i + 2 < bytes.length ? bytes[i + 2] : null;
44	
45	    result += chars[a >> 2];
46	    result += chars[((a & 3) << 4) | (b !== null ? b >> 4 : 0)];
47	
48	    if (b === null) {
49	      result += "==";
50	    } else {
51	      result += chars[((b & 15) << 2) | (c !== null ? c >> 6 : 0)];
52	      if (c === null) {
53	        result += "=";
54	      } else {
55	        result += chars[c & 63];
56	      }
57	    }
58	  }
59	  return result;
60	}
61	
62	function buildSvgSrc(name: IconName, colorHex: string): string {
63	  const icon = ICON_PATHS[name];
64	  if (!icon) return "";
65	
66	  const svg = [
67	    '<svg xmlns="http://www.w3.org/2000/svg"',
68	    ' width="24" height="24" viewBox="0 0 24 24"',
69	    ' fill="none"',
70	    ' stroke="' + colorHex + '"',
71	    ' stroke-width="2"',
72	    ' stroke-linecap="round"',
73	    ' stroke-linejoin="round"',
74	    ">",
75	    icon.paths.replace(new RegExp(PLACEHOLDER, "g"), colorHex),
76	    "</svg>",
77	  ].join("");
78	
79	  return "data:image/svg+xml;base64," + toBase64(svg);
80	}
81	
82	export default function Icon({ name, size = 48, color = "primary" }: IconProps) {
83	  const colorHex = COLOR_MAP[color];
84	  const src = buildSvgSrc(name, colorHex);
85	
86	  return (
87	    <Image
88	      src={src}
89	      mode="aspectFit"
90	      style={{ width: size + "rpx", height: size + "rpx" }}
91	    />
92	  );
93	}
